#!/usr/bin/env bash
# CI-triggered deploy script — runs on target server after SCP from GitLab Runner.
#
# Usage: SHB_VERSION=shb_v1.2.1 bash /tmp/ci-deploy.sh
#
# Server directory structure (must match on ALL target servers):
#   /root/Documents/plane-offline-pack/plane-app/
#   ├── docker-compose.yaml       ← base (plane-selfhost)
#   ├── docker-compose.shb.yml   ← static overlay (from initial deploy)
#   ├── docker-compose.ci.yml    ← generated by this script on each deploy
#   ├── plane.env                ← environment variables
#   ├── dist/                    ← tar.gz archives (initial deploy)
#   ├── scripts/
#   └── archive/
#
# Proxy config (separate, managed manually):
#   /opt/shb-deploy/plane-app/proxy/Caddyfile
#   /opt/certs/                              ← TLS certificates
#
# /tmp/plane-deploy/*.tar.gz — 3 images uploaded by GitLab CI Runner

set -euo pipefail

SHB_VERSION="${SHB_VERSION:?SHB_VERSION env var is required}"
# Override via env var for non-standard setups (e.g. VPS test: PLANE_DIR=/home/user/plane-app)
PLANE_DIR="${PLANE_DIR:-/root/Documents/plane-offline-pack/plane-app}"
IMAGES_DIR="/tmp/plane-deploy"
ENV_FILE="${PLANE_DIR}/plane.env"
BASE_COMPOSE="${PLANE_DIR}/docker-compose.yaml"
SHB_COMPOSE="${PLANE_DIR}/docker-compose.shb.yml"
CI_COMPOSE="${PLANE_DIR}/docker-compose.ci.yml"

# ── Preflight ─────────────────────────────────────────────────────────────────
command -v docker >/dev/null 2>&1 || { echo "ERROR: docker not found"; exit 1; }
docker compose version >/dev/null 2>&1 || { echo "ERROR: docker compose v2 not found"; exit 1; }
[ -d "${PLANE_DIR}" ]    || { echo "ERROR: ${PLANE_DIR} not found. Run initial deploy first."; exit 1; }
[ -f "${ENV_FILE}" ]     || { echo "ERROR: ${ENV_FILE} not found."; exit 1; }
[ -f "${BASE_COMPOSE}" ] || { echo "ERROR: ${BASE_COMPOSE} not found."; exit 1; }
[ -f "${SHB_COMPOSE}" ]  || { echo "ERROR: ${SHB_COMPOSE} not found. Run initial deploy first."; exit 1; }

echo "========================================="
echo " CI Deploy"
echo "========================================="
echo " Version: ${SHB_VERSION}"
echo " Server : $(hostname)"
echo "========================================="
echo ""

# ── Step 1: Load Docker images ────────────────────────────────────────────────
echo "[1/5] Loading Docker images from ${IMAGES_DIR}/ ..."
LOADED=0
for f in "${IMAGES_DIR}"/*.tar.gz; do
  [ -f "$f" ] || continue
  docker load < "$f"
  echo "  ✓ Loaded $(basename "$f")"
  LOADED=$((LOADED + 1))
done
[ "${LOADED}" -gt 0 ] || { echo "ERROR: No tar.gz files found in ${IMAGES_DIR}/"; exit 1; }
echo ""

# ── Step 2: Persist images to PLANE_DIR/dist/ (for rollback / re-deploy) ──────
echo "[2/5] Copying images + version to ${PLANE_DIR}/dist/ ..."
mkdir -p "${PLANE_DIR}/dist"
cp -f "${IMAGES_DIR}"/*.tar.gz "${PLANE_DIR}/dist/"
# Copy .shb-version so the server always reflects what's deployed
cp -f "${IMAGES_DIR}/.shb-version" "${PLANE_DIR}/dist/.shb-version" 2>/dev/null || true
echo "  ✓ Images + .shb-version saved to ${PLANE_DIR}/dist/"
echo ""

# ── Step 3: Generate CI compose override ─────────────────────────────────────
echo "[3/5] Generating ${CI_COMPOSE} ..."
cat > "${CI_COMPOSE}" << COMPOSE_EOF
# Auto-generated by GitLab CI — version: ${SHB_VERSION}
# Do not edit manually — overwritten on every deploy.
services:
  web:
    image: makeplane/plane-frontend:${SHB_VERSION}
  admin:
    image: makeplane/plane-admin:${SHB_VERSION}
  api:
    image: makeplane/plane-backend:${SHB_VERSION}
  worker:
    image: makeplane/plane-backend:${SHB_VERSION}
  beat-worker:
    image: makeplane/plane-backend:${SHB_VERSION}
  migrator:
    image: makeplane/plane-backend:${SHB_VERSION}
COMPOSE_EOF
echo "  ✓ ${CI_COMPOSE} written"
echo ""

COMPOSE_CMD="docker compose --env-file ${ENV_FILE} -f ${BASE_COMPOSE} -f ${SHB_COMPOSE} -f ${CI_COMPOSE}"

# ── Step 3: Run Django migrations ─────────────────────────────────────────────
echo "[4/5] Running Django migrations ..."
${COMPOSE_CMD} up -d migrator --force-recreate --no-build
echo "  Waiting for migrator to complete ..."
${COMPOSE_CMD} wait migrator || {
  echo "❌ Migration failed! Aborting deploy to protect data integrity."
  echo "   Logs: docker compose --env-file ${ENV_FILE} -f ${BASE_COMPOSE} -f ${SHB_COMPOSE} -f ${CI_COMPOSE} logs migrator"
  exit 1
}
echo "  ✓ Migrations complete"
echo ""

# ── Step 4: Deploy 3 dynamic services ────────────────────────────────────────
echo "[5/5] Deploying web, admin, api, worker, beat-worker ..."
${COMPOSE_CMD} up -d web admin api worker beat-worker --force-recreate --no-build
echo ""

echo "========================================="
echo " Deploy Complete — ${SHB_VERSION}"
echo "========================================="
echo ""
${COMPOSE_CMD} ps
